import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

export default function AdminDashboard() {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [pendingCAdmins, setPendingCAdmins] = useState([]);
  const [pendingCommunities, setPendingCommunities] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [statsRes, pendingUsersRes, pendingComRes] = await Promise.all([
        api.get('/users/stats'),
        api.get('/users/pending-community-admins'),
        api.get('/communities/all?status=pending'),
      ]);
      setStats(statsRes.data.data);
      setPendingCAdmins(pendingUsersRes.data.data || []);
      setPendingCommunities(pendingComRes.data.data || []);
    } catch (err) {
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const approveUser = async (id, name) => {
    try {
      await api.put(`/users/${id}/approve`);
      toast.success(`${name} approved successfully`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to approve');
    }
  };

  const rejectUser = async (id, name) => {
    const reason = prompt(`Reason for rejecting ${name}:`);
    if (reason === null) return;
    try {
      await api.put(`/users/${id}/reject`, { reason });
      toast.success(`${name} rejected`);
      fetchData();
    } catch (err) {
      toast.error('Failed to reject');
    }
  };

  if (loading) return <div className="loading-screen"><div className="spinner" /><span>Loading Dashboard...</span></div>;

  return (
    <div style={{ padding: '32px 32px 64px' }}>
        {/* Header */}
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>
                ADMIN <span className="gradient-text">DASHBOARD</span>
              </h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>
                Welcome back, {user?.name} — System Administration
              </p>
            </div>
            <div style={{ display: 'flex', gap: 10 }}>
              <Link to="/admin/users" className="btn btn-outline">Manage Users</Link>
              <Link to="/admin/communities" className="btn btn-primary">Manage Communities</Link>
            </div>
          </div>
        </div>

        {/* Stats Grid */}
        {stats && (
          <div className="grid grid-4" style={{ marginBottom: 40 }}>
            {[
              { label: 'Total Users', value: stats.total, color: 'var(--purple-light)' },
              { label: 'Pending Approval', value: stats.pending, color: 'var(--warning)' },
              { label: 'Community Admins', value: stats.communityAdmins, color: 'var(--pink-accent)' },
              { label: 'Students', value: stats.students, color: 'var(--cyan-accent)' },
            ].map((s, i) => (
              <div key={i} className="stat-card">
                <div className="stat-value" style={{ color: s.color }}>{s.value}</div>
                <div className="stat-label">{s.label}</div>
              </div>
            ))}
          </div>
        )}

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 28 }}>
          {/* Pending Community Admin Approvals */}
          <div>
            <div className="flex-between" style={{ marginBottom: 16 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>
                Pending Community Admins
                {pendingCAdmins.length > 0 && (
                  <span style={{ marginLeft: 10, background: 'var(--warning)', color: 'black', borderRadius: 100, padding: '2px 8px', fontSize: '0.7rem' }}>
                    {pendingCAdmins.length}
                  </span>
                )}
              </h3>
              <Link to="/admin/users?role=community_admin&status=pending" style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>View All →</Link>
            </div>

            {pendingCAdmins.length === 0 ? (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-state-icon">✅</div>
                  <div className="empty-state-text">No pending approvals</div>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {pendingCAdmins.slice(0, 5).map(u => (
                  <div key={u._id} className="card" style={{ padding: '16px 20px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 10 }}>
                      <div className="avatar">{u.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{u.name}</div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{u.email}</div>
                      </div>
                      <span className="badge badge-pending">Pending</span>
                    </div>
                    {u.communityName && (
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: 12, padding: '8px 12px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)' }}>
                        <strong style={{ color: 'var(--purple-light)' }}>Community:</strong> {u.communityName}
                        <br />
                        <strong style={{ color: 'var(--purple-light)' }}>Category:</strong> {u.communityCategory}
                        <br />
                        <span style={{ color: 'var(--text-muted)' }}>{u.communityDescription?.substring(0, 80)}...</span>
                      </div>
                    )}
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button onClick={() => approveUser(u._id, u.name)} className="btn btn-success btn-sm" style={{ flex: 1, justifyContent: 'center' }}>✓ Approve</button>
                      <button onClick={() => rejectUser(u._id, u.name)} className="btn btn-danger btn-sm" style={{ flex: 1, justifyContent: 'center' }}>✗ Reject</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Pending Community Approvals */}
          <div>
            <div className="flex-between" style={{ marginBottom: 16 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>
                Pending Communities
                {pendingCommunities.length > 0 && (
                  <span style={{ marginLeft: 10, background: 'var(--warning)', color: 'black', borderRadius: 100, padding: '2px 8px', fontSize: '0.7rem' }}>
                    {pendingCommunities.length}
                  </span>
                )}
              </h3>
              <Link to="/admin/communities" style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>View All →</Link>
            </div>

            {pendingCommunities.length === 0 ? (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-state-icon">✅</div>
                  <div className="empty-state-text">No pending communities</div>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {pendingCommunities.slice(0, 5).map(c => (
                  <div key={c._id} className="card" style={{ padding: '16px 20px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 10 }}>
                      <div className="avatar" style={{ borderRadius: 8, background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))' }}>{c.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{c.name}</div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>by {c.admin?.name}</div>
                      </div>
                      <span className={`badge badge-${c.category?.toLowerCase()}`}>{c.category}</span>
                    </div>
                    <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
                      {c.description?.substring(0, 100)}...
                    </p>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button onClick={async () => {
                        try { await api.put(`/communities/${c._id}/approve`); toast.success('Community approved!'); fetchData(); }
                        catch (e) { toast.error('Failed to approve'); }
                      }} className="btn btn-success btn-sm" style={{ flex: 1, justifyContent: 'center' }}>✓ Approve</button>
                      <button className="btn btn-danger btn-sm" style={{ flex: 1, justifyContent: 'center' }} onClick={async () => {
                        const reason = prompt('Rejection reason:');
                        if (!reason) return;
                        try { await api.put(`/communities/${c._id}/reject`, { reason }); toast.success('Community rejected'); fetchData(); }
                        catch (e) { toast.error('Failed'); }
                      }}>✗ Reject</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Quick Links */}
        <div style={{ marginTop: 40 }}>
          <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', marginBottom: 16 }}>QUICK ACTIONS</h3>
          <div className="grid grid-4">
            {[
              { to: '/admin/users', label: 'All Users', icon: '👤', desc: `${stats?.total || 0} total` },
              { to: '/admin/users?status=pending', label: 'Pending Users', icon: '⏳', desc: `${stats?.pending || 0} waiting` },
              { to: '/admin/communities', label: 'Communities', icon: '🏛️', desc: 'Manage all' },
              { to: '/clubs', label: 'Public View', icon: '🌐', desc: 'See portal' },
            ].map((item, i) => (
              <Link key={i} to={item.to} style={{ textDecoration: 'none' }}>
                <div className="card" style={{ cursor: 'pointer', textAlign: 'center', padding: '20px 16px' }}>
                  <div style={{ fontSize: '2rem', marginBottom: 10 }}>{item.icon}</div>
                  <div style={{ fontWeight: 700, fontSize: '0.875rem', marginBottom: 4 }}>{item.label}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{item.desc}</div>
                </div>
              </Link>
            ))}
          </div>
      </div>
    </div>
  );
}
